import{_ as o,o as t,c as i,a2 as n}from"./chunks/framework.BWuWLRhz.js";const h=JSON.parse('{"title":"Epic: Notification Center","description":"","frontmatter":{},"headers":[],"relativePath":"epics/notification-center.md","filePath":"epics/notification-center.md"}'),a={name:"epics/notification-center.md"};function s(r,e,c,d,l,p){return t(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="epic-notification-center" tabindex="-1">Epic: Notification Center <a class="header-anchor" href="#epic-notification-center" aria-label="Permalink to &quot;Epic: Notification Center&quot;">​</a></h1><blockquote><p>Per-user notification inbox, toasts, web push, and a pluggable transport layer so plugins can reach users across any delivery channel.</p></blockquote><h2 id="status" tabindex="-1">Status <a class="header-anchor" href="#status" aria-label="Permalink to &quot;Status&quot;">​</a></h2><p>⏳ In Progress</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The Notification Center gives plugins a single <code>sdk.notifications.send()</code> call that fans out to the user&#39;s in-app inbox, a toast if they are active, and a background push notification if they have opted in. The first two tasks built the inbox, bell chrome, Toast primitive, admin broadcast, and VAPID-based web push. Epic task 4.3 replaces the polling SSE backend with a real event-driven broker — operators choose between in-process EventEmitter (zero infra) or Redis Pub/Sub (multi-process deployments).</p><h2 id="tasks" tabindex="-1">Tasks <a class="header-anchor" href="#tasks" aria-label="Permalink to &quot;Tasks&quot;">​</a></h2><h4 id="✅-4-1-—-notification-center" tabindex="-1">✅ 4.1 — Notification Center <a class="header-anchor" href="#✅-4-1-—-notification-center" aria-label="Permalink to &quot;✅ 4.1 — Notification Center&quot;">​</a></h4><p><strong>Goal:</strong> A per-user notification inbox with a bell + panel, toasts, the <code>sdk.notifications</code> send surface, and admin broadcast.</p><p><strong>Deliverables:</strong></p><ul><li>Tenant-scoped <code>notifications</code> table (read/unread/dismiss) + notification prefs; clearly differentiated from the activity log</li><li>Implement <code>sdk.notifications.send</code> (send-only for plugins; runtime injects source/tenant); platform-owned fan-out (inbox + toast if active)</li><li>Bell + panel in chrome (sidebar/header, RFC 0011 icon, RFC 0013 Drawer on mobile) + a <code>Toast</code> primitive; <code>/api/account/notifications</code> routes</li><li>Admin broadcast with guardrails (audited via RFC 0005, rate-limited, audience-scoped, user opt-out); admin-selectable transport (polling default / WebSocket) + per-user poll interval</li></ul><p><strong>Dependencies:</strong> Task 0.5.05 (<code>sdk.db</code>), Task 0.5.12 (audit), Task 0.5.17 (icons)</p><p><strong>SRS reference:</strong> RFC 0015</p><p><strong>Review checklist:</strong></p><ul><li>A plugin send appears in the inbox + bell badge + a toast; an admin broadcast reaches all users and is audited; users can mute the announcement category</li></ul><hr><h4 id="✅-4-2-—-web-push-notifications" tabindex="-1">✅ 4.2 — Web Push notifications <a class="header-anchor" href="#✅-4-2-—-web-push-notifications" aria-label="Permalink to &quot;✅ 4.2 — Web Push notifications&quot;">​</a></h4><p><strong>Goal:</strong> Background delivery of inbox notifications via Web Push (VAPID + service worker).</p><p><strong>Deliverables:</strong></p><ul><li>VAPID keys as optional no-default env secrets (push disabled when unset); a <code>customWorkerSrc</code> push/<code>notificationclick</code> handler; <code>push_subscriptions</code> table + helpers</li><li>Account opt-in (permission + subscribe) with the iOS-installed-PWA caveat; <code>web-push</code> send on the RFC 0015 fan-out (subject to category prefs); prune on <code>410</code></li><li>Plugins never touch push — the platform fans out from the inbox</li></ul><p><strong>Dependencies:</strong> Task 1.0.04 (Notification Center)</p><p><strong>SRS reference:</strong> RFC 0016</p><p><strong>Review checklist:</strong></p><ul><li>Enabling push delivers a background notification; an unsubscribed device gets none; secrets stay in env (push off when unset)</li></ul><hr><h4 id="📋-4-3-—-notification-center-pluggable-pub-sub-transport" tabindex="-1">📋 4.3 — Notification Center: pluggable pub/sub transport <a class="header-anchor" href="#📋-4-3-—-notification-center-pluggable-pub-sub-transport" aria-label="Permalink to &quot;📋 4.3 — Notification Center: pluggable pub/sub transport&quot;">​</a></h4><p><strong>Goal:</strong> Replace the Notification Center&#39;s DB-polling SSE backend with a real event-driven pub/sub broker. Polling stays the default (<code>NOTIFICATION_TRANSPORT=polling</code>); operators opt in to instant push delivery via <code>sse</code> (in-process EventEmitter, no new infra) or <code>redis</code> (Redis Pub/Sub, for multi-process/clustered deployments). Resolves RFC 0015&#39;s deferred transport decision.</p><p><strong>Deliverables:</strong></p><ul><li><code>runtime/src/notification-broker.ts</code> — <code>NotificationBroker</code> interface + singleton <code>initBroker()</code> / <code>getBroker()</code> accessors.</li><li><code>runtime/src/brokers/in-process.ts</code> — <code>InProcessBroker</code> (Node.js <code>EventEmitter</code>, <code>setMaxListeners(0)</code>, no deps).</li><li><code>runtime/src/brokers/redis.ts</code> — <code>RedisBroker</code> (<code>ioredis</code> PUBLISH/SUBSCRIBE, two dedicated connections); loaded via dynamic <code>import()</code> so <code>ioredis</code> is truly optional.</li><li><code>ioredis</code> added as <code>optionalDependencies</code> in <code>runtime/package.json</code>.</li><li><code>runtime/instrumentation.ts</code> — <code>register()</code> reads <code>NOTIFICATION_TRANSPORT</code> and <code>REDIS_URL</code>, initialises broker, calls <code>broker.close()</code> on <code>SIGTERM</code>.</li><li><code>runtime/src/sdk-host.ts</code> — <code>notifications.send()</code> calls <code>broker.publish()</code> after DB write (no-op when broker is null / polling mode).</li><li><code>runtime/app/api/account/notifications/stream/route.ts</code> — rewired to subscribe to the broker; 503 when <code>NOTIFICATION_TRANSPORT=polling</code>; 25 s heartbeat comment line to beat proxy idle timeouts; <code>X-Accel-Buffering: no</code> header.</li><li><code>runtime/app/api/account/notifications/route.ts</code> — response gains <code>transport: &#39;polling&#39; | &#39;sse&#39;</code> field (Node.js runtime reads env at request time).</li><li><code>plugins/account</code> — bell component reads <code>transport</code> from initial fetch: in <code>sse</code> mode, connects <code>EventSource</code> instead of polling; three-error fallback to polling.</li><li><code>GET /api/admin/health</code> — <code>notifications: { transport, brokerConnected }</code> section.</li><li>New env vars: <code>NOTIFICATION_TRANSPORT</code> (default <code>polling</code>), <code>REDIS_URL</code>, optional <code>NOTIFICATION_HEARTBEAT_INTERVAL</code> (default <code>25000</code>) — added to <code>.env.example</code> and <code>docs/self-hosting.md</code>.</li><li><code>docker-compose.prod.yml</code> — commented-out <code>redis</code> service block; commented <code>NOTIFICATION_TRANSPORT=redis</code> + <code>REDIS_URL</code> lines for operators to activate.</li><li><code>docs/self-hosting.md</code> — new &quot;Notification transport&quot; section (proxy config table for nginx / Caddy / Traefik / AWS ALB; SSE vs polling tradeoffs; Redis setup steps).</li><li>Deprecates: RFC 0015&#39;s planned <code>notification_transport</code> key in <code>platform_settings</code> (never written; replaced by the env var).</li></ul><p><strong>Root version bump:</strong> root <code>package.json</code> — patch (one pre-v1 hardening task)</p><p><strong>Dependencies:</strong> Task 0.7.01 (Notification Center — <code>sdk.notifications.send()</code> and the existing SSE route shape this task rewires)</p><p><strong>SRS reference:</strong> RFC 0034, RFC 0015 (open question 2 resolved)</p><p><strong>Review checklist:</strong></p><ul><li><code>NOTIFICATION_TRANSPORT=polling</code> (default): SSE endpoint returns 503; bell polls at user&#39;s configured interval; behaviour identical to pre-RFC baseline</li><li><code>NOTIFICATION_TRANSPORT=sse</code>: <code>EventSource</code> connection opens; <code>sdk.notifications.send()</code> delivers notification to bell in &lt; 1 s (no poll wait); multiple tabs all receive</li><li><code>NOTIFICATION_TRANSPORT=redis</code> + <code>REDIS_URL</code> set: cross-process delivery verified (send from process A, client on process B receives)</li><li><code>NOTIFICATION_TRANSPORT=redis</code>, Redis down: notification written to DB; SSE push degrades gracefully; health reports <code>brokerConnected: false</code></li><li><code>GET /api/admin/health</code> returns correct <code>notifications.transport</code> and <code>brokerConnected</code></li><li><code>pnpm format:check &amp;&amp; pnpm lint &amp;&amp; pnpm typecheck &amp;&amp; pnpm test</code></li></ul><hr><h2 id="related-rfcs" tabindex="-1">Related RFCs <a class="header-anchor" href="#related-rfcs" aria-label="Permalink to &quot;Related RFCs&quot;">​</a></h2><ul><li><a href="./../rfcs/0015-notification-center.html">RFC 0015 — Notification Center</a></li><li><a href="./../rfcs/0016-web-push.html">RFC 0016 — Web Push</a></li><li><a href="./../rfcs/0034-notification-transport.html">RFC 0034 — Notification transport</a></li></ul><h2 id="related-docs" tabindex="-1">Related Docs <a class="header-anchor" href="#related-docs" aria-label="Permalink to &quot;Related Docs&quot;">​</a></h2><ul><li><a href="./../self-hosting.html">self-hosting.md — VAPID and transport config</a></li><li><a href="./../plugin-development.html">plugin-development.md — <code>sdk.notifications</code></a></li></ul>',39)])])}const f=o(a,[["render",s]]);export{h as __pageData,f as default};
